def agora_brasilia():
    """Retorna a data/hora atual no horário oficial de Brasília, UTC-03:00."""
    return datetime.now(timezone.utc).astimezone(FUSO_HORARIO_BRASILIA)


def agora_iso():
    """Retorna data/hora atual de Brasília em ISO-8601 com deslocamento -03:00."""
    return agora_brasilia().replace(microsecond=0).isoformat()


def agora_texto_brasilia():
    """Retorna data/hora atual de Brasília para exibição."""
    return agora_brasilia().strftime("%d/%m/%Y %H:%M")


def hoje_ddmmaaaa():
    """Retorna a data atual de Brasília no formato dd/mm/aaaa."""
    return agora_brasilia().strftime("%d/%m/%Y")


def parse_data(valor):
    if valor is None or valor == "":
        return None

    if isinstance(valor, datetime):
        return valor.date()

    if isinstance(valor, date):
        return valor

    texto = str(valor).strip()

    for fmt in ("%d/%m/%Y", "%Y-%m-%d", "%d-%m-%Y", "%d/%m/%y"):
        try:
            return datetime.strptime(texto, fmt).date()
        except Exception:
            pass

    try:
        return pd.to_datetime(texto, dayfirst=True, errors="coerce").date()
    except Exception:
        return None


def data_para_exibir(valor):
    d = parse_data(valor)
    if d:
        return d.strftime("%d/%m/%Y")
    return ""


def formatar_data_hora_brasilia(valor):
    if valor is None or valor == "":
        return ""

    texto = str(valor).strip().replace("\n", "").replace("\r", "")
    if not texto:
        return ""

    if re.match(r"^\d{2}/\d{2}/\d{4} \d{2}:\d{2}$", texto):
        return texto

    try:
        if texto.endswith("Z"):
            texto = texto[:-1] + "+00:00"

        if " " in texto and "T" not in texto:
            texto = texto.replace(" ", "T")

        dt = datetime.fromisoformat(texto)

        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)

        return dt.astimezone(FUSO_HORARIO_BRASILIA).strftime("%d/%m/%Y %H:%M")
    except Exception:
        return texto


def iso_para_exibir(valor):
    return formatar_data_hora_brasilia(valor)





def normalizar_complexidade(valor):
    texto = str(valor or "").strip()
    for item in COMPLEXIDADES_ATENDIMENTO:
        if texto.casefold() == item.casefold():
            return item
    return "Não informada"


def perfil_normalizado(valor):
    texto = str(valor or "").strip()
    if texto in PERFIS_USUARIO:
        return texto
    if texto == "Administrador":
        return "Administrador geral"
    if texto == "Usuário":
        return "Operador SEPRO"
    return "Operador SEPRO"


def usuario_pode_ver_secao(secao):
    usuario = usuario_logado()
    if not usuario:
        return False

    perfil = perfil_normalizado(usuario.get("perfil"))
    secao_usuario = normalizar_secao(usuario.get("secao_operador") or usuario.get("secao") or "SEPRO")
    secao = normalizar_secao(secao)

    if perfil in ("Administrador geral", "Administrador", "Consulta"):
        return True

    # Perfis no formato "Chefia SEOCE", "Operador SEPRO" etc.
    for prefixo in ("Chefia ", "Operador "):
        if perfil.startswith(prefixo):
            secao_perfil = normalizar_secao(perfil.replace(prefixo, "", 1))
            return secao_perfil == secao

    return secao_usuario == secao


