        ("Urgentes abertas", numero_br(ind["urgentes"]), "#B91C1C"),
        ("Prazo vencido", numero_br(ind["prazo_vencido"]), "#991B1B"),
        ("Sem responsável", numero_br(ind["sem_responsavel"]), "#C2410C"),
        ("Meus pendentes", numero_br(ind["meus"]), "#7A60A8"),
